sql:
SELECT AVG(six_months) AS average_grease_consumption, bearing_id
FROM grease_consumption
WHERE bearing_id = 1;

SELECT bearing_id, bearing_no, description
FROM bearings
WHERE max_speed > 6000;

SELECT bearing_id, AVG(ten_months) AS avg_grease_consumption_10_months
FROM grease_consumption
GROUP BY bearing_id;

external_knowledge:
- "Heart of each mechanical soul" metaphorically refers to each bearing number (bearing_no).;
- "Total grease consumption" signifies the sum of grease used after 10 months (ten_months).;
- "Average cost of keeping them in the dance of motion" refers to the average cost per unit of maintenance (cost_per_unit).;
- "Perfect decade" metaphorically refers to the 10-month period mentioned in the query.;

sql:
SELECT cost_type, SUM(total_cost) AS total_maintenance_cost
FROM cost_analysis
GROUP BY cost_type;
